{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://github.com/Mega-Therion/OmegA-Architecture/schemas/claim_graph.schema.json",
  "title": "ClaimGraph",
  "description": "Directed graph of claims with evidence edges and aggregate metrics",
  "type": "object",
  "required": ["claims", "edges"],
  "properties": {
    "claims": {
      "type": "object",
      "additionalProperties": { "$ref": "claim_node.schema.json" }
    },
    "edges": {
      "type": "array",
      "items": { "$ref": "evidence_edge.schema.json" }
    },
    "grounding_ratio": { "type": "number", "minimum": 0, "maximum": 1 },
    "total_claims": { "type": "integer", "minimum": 0 },
    "total_edges": { "type": "integer", "minimum": 0 },
    "contradictions": { "type": "integer", "minimum": 0 },
    "unresolved": { "type": "integer", "minimum": 0 }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://github.com/Mega-Therion/OmegA-Architecture/schemas/session_snapshot.schema.json",
  "title": "SessionSnapshot",
  "description": "Point-in-time snapshot of a session state for persistence and recovery",
  "type": "object",
  "required": ["snapshot_id", "session_id", "state"],
  "properties": {
    "snapshot_id": { "type": "string" },
    "session_id": { "type": "string" },
    "state": { "$ref": "session_state.schema.json" },
    "created_at": { "type": "number" }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://github.com/Mega-Therion/OmegA-Architecture/schemas/task_object.schema.json",
  "title": "TaskObject",
  "description": "Structured task with lifecycle state machine, parent-child relationships, and outputs",
  "type": "object",
  "required": ["task_id", "objective", "status"],
  "properties": {
    "task_id": { "type": "string" },
    "parent_id": { "type": ["string", "null"] },
    "objective": { "type": "string" },
    "constraints": { "type": "array", "items": { "type": "string" } },
    "success_criteria": { "type": "array", "items": { "type": "string" } },
    "unknowns": { "type": "array", "items": { "type": "string" } },
    "dependencies": { "type": "array", "items": { "type": "string" } },
    "status": { "type": "string", "enum": ["queued", "running", "blocked", "awaiting_approval", "completed", "failed"] },
    "transitions": {
      "type": "array",
      "items": { "$ref": "task_transition.schema.json" }
    },
    "outputs": { "type": "array", "items": { "type": "object" } },
    "run_ids": { "type": "array", "items": { "type": "string" } },
    "created_at": { "type": "number" },
    "updated_at": { "type": "number" }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://github.com/Mega-Therion/OmegA-Architecture/schemas/task_transition.schema.json",
  "title": "TaskTransition",
  "description": "A single status transition in a task's lifecycle",
  "type": "object",
  "required": ["from_status", "to_status", "reason"],
  "properties": {
    "from_status": { "type": "string", "enum": ["queued", "running", "blocked", "awaiting_approval", "completed", "failed"] },
    "to_status": { "type": "string", "enum": ["queued", "running", "blocked", "awaiting_approval", "completed", "failed"] },
    "reason": { "type": "string" },
    "timestamp": { "type": "number" }
  }
}
